def inspect_jwt_without_verification(token: str) -> Dict[str, Any]:
    """
    Inspect JWT token contents WITHOUT verification.
    
    WARNING: This function does NOT verify the token signature or claims.
    Use ONLY for debugging purposes to inspect token structure.
    NEVER use unverified tokens for authentication or authorization decisions.
    
    Args:
        token: JWT token string to inspect
        
    Returns:
        Dictionary containing header and payload (unverified)
    """
    print("\n" + "!" * 60)
    print("WARNING: INSPECTING TOKEN WITHOUT VERIFICATION")
    print("This token data is UNVERIFIED and UNTRUSTED")
    print("DO NOT use for authentication or authorization decisions")
    print("!" * 60 + "\n")
    
    try:
        header = jwt.get_unverified_header(token)
        payload = jwt.decode(token, options={"verify_signature": False})
        
        print("=== Unverified Token Contents ===")
        print("\nHeader:")
        print(json.dumps(header, indent=2))
        print("\nPayload:")
        print(json.dumps(payload, indent=2))
        print("=" * 40 + "\n")
        
        return {
            'header': header,
            'payload': payload
        }
    except Exception as e:
        print(f"ERROR: Failed to decode token - {str(e)}")
        raise


